def normalize(ans: str):
    """Normalize answers like:
    '4, 6, 9' -> ['4', '6', '9']
    '9 6 4'   -> ['4', '6', '9']
    """
    if not isinstance(ans, str):
        return []

    parts = re.split(r"[,\s]+", ans.strip())
    return sorted(p for p in parts if p)


def extract_model_answer(text: str):
    """Extract final answer from model output with nested brace support."""
    if not isinstance(text, str):
        return ""

    pattern = r"\\boxed\{"
    matches = list(re.finditer(pattern, text))
    if not matches:
        return ""

    last_match = matches[-1]
    start = last_match.end()

    brace_count = 1
    i = start
    while i < len(text) and brace_count > 0:
        if text[i] == '{':
            brace_count += 1
        elif text[i] == '}':
            brace_count -= 1
        i += 1

    if brace_count == 0:
        return text[start:i-1].strip()

    return ""


def grade(sample, item):
    """RFT grading entrypoint
    sample["output_text"] -> model generated text
    item["answer"]        -> ground truth answer
    """

    pred_raw = extract_model_answer(sample.get("output_text", ""))
    ref_raw = item.get("answer", "")

    if not pred_raw or not ref_raw:
        return 0.0

    pred = normalize(pred_raw)
    ref = normalize(ref_raw)

    return 1.0 if pred == ref else 0.0

